using System;
using System.Linq;

namespace Scriptome.Limbic.Algoritmos
{
    /// <summary>
    /// ALGORITMO: BURST (Tensão Física)
    /// Analisa a densidade e brevidade das sentenças para determinar o ritmo biológico.
    /// </summary>
    public class CalculadoraTensao
    {
        public double Calcular(string texto)
        {
            if (string.IsNullOrWhiteSpace(texto)) return 0;

            // Limpeza básica
            var sentencas = texto.Split(new[] { '.', '!', '?' }, StringSplitOptions.RemoveEmptyEntries);
            var palavras = texto.Split(new[] { ' ', '\n', '\r' }, StringSplitOptions.RemoveEmptyEntries);

            if (palavras.Length == 0) return 0;

            // 1. Métrica de Brevidade (Frases Curtas = Alta Tensão)
            double mediaPalavrasPorSentenca = (double)palavras.Length / Math.Max(1, sentencas.Length);
            double scoreBrevidade = Math.Max(0, 100 - (mediaPalavrasPorSentenca * 5));
            // *5 significa que frases com >20 palavras zeram a brevidade.

            // 2. Métrica de Densidade (Palavras Curtas/Monossílabas = Ação Rápida)
            int monossilabos = palavras.Count(p => p.Length <= 3);
            double ratioMonossilabos = (double)monossilabos / palavras.Length;
            double scoreDensidade = ratioMonossilabos * 100;

            // Fusão: 60% Brevidade (Corte) + 40% Densidade (Velocidade)
            return Math.Round((scoreBrevidade * 0.6) + (scoreDensidade * 0.4), 2);
        }
    }
}

using System;
using System.Linq;
using System.Text.RegularExpressions;

namespace Scriptome.Limbic.Algoritmos
{
    /// <summary>
    /// ALGORITMO: MODALIDADE (Incerteza/Conflito Interno)
    /// Detecta estruturas de dúvida, possibilidade e negação.
    /// </summary>
    public class CalculadoraModalidade
    {
        private static readonly Regex _padraoDuvida = new Regex(
            @"\b(talvez|acho|pode ser|quem sabe|possível|provável|será|suponho|parece|quase)\b",
            RegexOptions.Compiled | RegexOptions.IgnoreCase);

        private static readonly Regex _padraoNegacao = new Regex(
            @"\b(não|nunca|jamais|nada|nem|ninguém|tampouco)\b",
            RegexOptions.Compiled | RegexOptions.IgnoreCase);

        public double Calcular(string texto)
        {
            if (string.IsNullOrWhiteSpace(texto)) return 0;

            int totalPalavras = texto.Split(' ').Length;

            // Contagem de Ocorrências
            int duvidas = _padraoDuvida.Matches(texto).Count;
            int negacoes = _padraoNegacao.Matches(texto).Count;
            int reticencias = Regex.Matches(texto, @"\.\.\.").Count;

            // Peso Específico
            double pesoDuvida = duvidas * 3.0;     // Dúvida pesa muito
            double pesoReticencia = reticencias * 2.0; // Pausa dramática
            double pesoNegacao = negacoes * 1.0;   // Negação é conflito leve

            double scoreBruto = pesoDuvida + pesoReticencia + pesoNegacao;

            // Normalização Logística (Sigmóide Simplificada para 0-10)
            // Um texto precisa de densidade razoável para atingir 10
            double densidade = scoreBruto / Math.Max(5, totalPalavras); // Divisor 5 evita explosão em frases curtas

            return Math.Min(10, Math.Round(densidade * 10, 2));
        }
    }
}

using Scriptome.Limbic.Dados;
using Scriptome.Linguistica; // ACESSO AOS TOKENS
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Limbic.Algoritmos
{
    public static class HeuristicaContextual
    {
        private static readonly Dictionary<string, double> _modificadores = new()
        {
            // Intensificadores (+ Força)
            { "MUITO", 1.0 }, { "EXTREMAMENTE", 1.0 }, { "TOTALMENTE", 1.0 },
            { "COMPLETAMENTE", 1.0 }, { "DEMAIS", 1.0 }, { "TÃO", 1.0 },
            { "SUPER", 1.0 }, { "HIPER", 1.0 }, { "REALMENTE", 1.0 },
            
            // Atenuadores (- Força)
            { "POUCO", -1.0 }, { "APENAS", -1.0 }, { "MEIO", -1.0 },
            { "QUASE", -1.0 }, { "LIGEIRAMENTE", -1.0 }, { "MENOS", -1.0 }
        };

        private static readonly HashSet<string> _negacoes = new()
        {
            "NÃO", "NAO", "NUNCA", "JAMAIS", "NEM", "TAMPOUCO", "SEM", "NENHUM"
        };

        /// <summary>
        /// Aplica VADER sobre uma lista de Tokens processados pelo Pipeline Linguístico.
        /// </summary>
        public static double CalcularScoreAjustado(double valorBase, IReadOnlyList<Token> tokens,  int indiceAlvo, ParametrosVader dna)
        {
            if (valorBase == 0) return 0;

            double escalarAcumulado = 0.0;
            double fatorNegacaoTotal = 1.0;
            int contagemModificadores = 0;
            bool negacaoEncontrada = false;

            // 1. JANELA DE CONTEXTO (Olha para trás)
            int inicio = Math.Max(0, indiceAlvo - dna.JanelaContexto);

            for (int i = indiceAlvo - 1; i >= inicio; i--)
            {
                Token t = tokens[i];
                string termo = t.Normalizado; // Usa o texto limpo e UPPERCASE
                double distancia = (indiceAlvo - i);

                // [REGRA 7] Interrupção por Pontuação (Token sabe se é pontuação)
                if (t.EhPontuacao) break;

                // [REGRA 6] Negação
                if (_negacoes.Contains(termo))
                {
                    negacaoEncontrada = true;
                    fatorNegacaoTotal = dna.FatorNegacao;
                    if (distancia > 1) fatorNegacaoTotal *= 0.9;
                }

                // [REGRA 1 e 10] Modificadores com Decaimento
                if (_modificadores.TryGetValue(termo, out double direcao))
                {
                    if (contagemModificadores >= 2) continue;

                    double forcaBase = (direcao > 0) ? dna.BoosterIntenso : dna.BoosterLeve;
                    double influencia = forcaBase * (1.0 / distancia);

                    escalarAcumulado += influencia;
                    contagemModificadores++;
                }
            }

            // [REGRA 2] Clamping
            escalarAcumulado = Math.Clamp(escalarAcumulado, -dna.MaxEscalar, dna.MaxEscalar);

            // [REGRA 5] Normalização Multiplicativa
            double multiplicadorContexto = 1.0 + (escalarAcumulado * dna.FatorEscala);
            if (multiplicadorContexto < 0.1) multiplicadorContexto = 0.1;

            double valorFinal = valorBase * multiplicadorContexto;

            if (negacaoEncontrada) valorFinal *= fatorNegacaoTotal;

            // [REGRA 4] Ênfase por ALL CAPS (Propriedade do Token)
            if (tokens[indiceAlvo].CaixaAlta)
            {
                valorFinal += (Math.Sign(valorFinal) * Math.Abs(valorFinal) * dna.BoosterCaixaAlta);
            }

            // [REGRA 3] Ênfase por Pontuação (Olha para frente, ex: "BOM!")
            // Verifica se o próximo token é pontuação de ênfase
            if (indiceAlvo + 1 < tokens.Count)
            {
                var prox = tokens[indiceAlvo + 1];
                if (prox.EhPontuacao && (prox.Original.Contains("!") || prox.Original.Contains("?")))
                {
                    double bonus = Math.Abs(valorFinal) * dna.BoosterPontuacao;
                    if (valorFinal > 0) valorFinal += bonus; else valorFinal -= bonus;
                }
            }

            // [REGRA 9] Proteção Final
            return Math.Clamp(valorFinal, -12.0, 12.0);
        }
    }
}

using System.Collections.Generic;

namespace Scriptome.Limbic.Algoritmos
{
    /// <summary>
    /// PROJETO CATALYST - Otimizador Morfológico.
    /// Responsável por reduzir variações de palavras (plurais, conjugações) à sua raiz léxica.
    /// Isso aumenta drasticamente o "Hit Rate" do banco de dados sem precisar cadastrar variações no Excel.
    /// </summary>
    public static class LematizadorCatalyst
    {
        // Lista de sufixos comuns em verbos e plurais do PT-BR, ordenados do maior para o menor.
        // A ordem importa: queremos remover o maior sufixo possível primeiro.
        private static readonly string[] _sufixos = new[]
        {
            // Verbos (Futuro/Condicional)
            "REMOS", "RÍAM", "RIAM", "REIS", 
            
            // Verbos (Gerúndio/Particípio)
            "NDO", "ADO", "IDO",
            
            // Verbos (Pretérito/Subjuntivo)
            "SSE", "STE", "RAM", "RÃO", "AVA", "IAM", "U-SE", "A-SE",
            
            // Verbos (Infinitivo com pronome)
            "R-ME", "R-TE", "R-SE", "R-NOS",
            
            // Plurais e Simples
            "RES", "TES", "REM", "IS", "AM", "EM", "ES", "OS", "AS", "S" // Cuidado com 'S' isolado
        };

        // Exceções que NÃO devem ser cortadas (Falsos positivos comuns)
        private static readonly HashSet<string> _excecoes = new()
        {
            "DEUS", "MAIS", "POIS", "APOS", "ALIAS", "ATRAS", "MES", "TRES",
            "LUZ", "PAZ", "CRUZ", "VOZ", "VEZ", "NOS", "VOS", "LULAS", "CAOS",
            "ONIBUS", "LAPIS", "TENIS", "VIRUS", "BONUS"
        };

        /// <summary>
        /// Tenta reduzir a palavra à sua raiz provável.
        /// </summary>
        public static string ObterRaiz(string palavra)
        {
            if (string.IsNullOrEmpty(palavra) || palavra.Length < 4)
                return palavra; // Não mexe em palavras curtas (ex: SOL, PAI)

            // 1. Checagem de Exceção (Proteção)
            if (_excecoes.Contains(palavra)) return palavra;

            // 2. Tentativa de Poda (Stemming)
            foreach (var sufixo in _sufixos)
            {
                if (palavra.EndsWith(sufixo))
                {
                    // Regra de Segurança: A raiz resultante deve ter pelo menos 3 letras
                    // Ex: "VENDO" (-NDO) -> "VE" (Muito curto, perigoso) -> Ignora
                    // Ex: "MATANDO" (-NDO) -> "MATA" (Ok)

                    int tamanhoRaiz = palavra.Length - sufixo.Length;

                    if (tamanhoRaiz >= 3)
                    {
                        string raiz = palavra.Substring(0, tamanhoRaiz);

                        // Correção ortográfica pós-corte
                        // Ex: "AMIGOS" (-S) -> "AMIGO" (Ok)
                        // Ex: "CORRESSE" (-SSE) -> "CORRE" (Ok)
                        // Ex: "FELIZES" (-ES) -> "FELIZ" (Ok)

                        return raiz;
                    }
                }
            }

            // 3. Regra Especial para 'R' final (Infinitivos)
            // Ex: AMAR -> AMA (Muitas vezes o Excel tem "AMA" ou "AMOR", mas não "AMAR")
            if (palavra.EndsWith("R") && palavra.Length > 4)
            {
                return palavra.Substring(0, palavra.Length - 1);
            }

            return palavra;
        }
    }
}

using System.Collections.Generic;

namespace Scriptome.Limbic.Algoritmos
{
    public class LematizadorVerbal
    {
        // Dicionário de Sufixos
        private static readonly Dictionary<string, string> RegrasSufixo = new Dictionary<string, string>
        {
            // 1ª Conjugação (-ar)
            { "ando", "ar" }, { "ou", "ar" }, { "ava", "ar" }, { "aram", "ar" }, { "arei", "ar" }, { "asse", "ar" },
            { "amos", "ar" }, { "aste", "ar" },
            // 2ª Conjugação (-er)
            { "endo", "er" }, { "eu", "er" }, { "ia", "er" }, { "eram", "er" }, { "erei", "er" }, { "esse", "er" },
            { "emos", "er" }, { "este", "er" }, { "era", "er" },
            // 3ª Conjugação (-ir)
            { "indo", "ir" }, { "iu", "ir" }, { "iram", "ir" }, { "irei", "ir" }, { "isse", "ir" },
            { "imos", "ir" }, { "iste", "ir" }
        };

        public string Lematizar(string token)
        {
            if (string.IsNullOrEmpty(token) || token.Length < 4) return token;

            foreach (var regra in RegrasSufixo)
            {
                if (token.EndsWith(regra.Key))
                {
                    var raiz = token.Substring(0, token.Length - regra.Key.Length);
                    return raiz + regra.Value;
                }
            }
            return token;
        }
    }
}

using Scriptome.Limbic.Dados;
using Scriptome.Limbic.Modelos;
using Scriptome.Linguistica;
using Scriptome.Limbic.Interfaces;
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Limbic.Algoritmos
{
    /// <summary>
    /// STRATEGY: DERIVA 6 (Sintático v1.2 - RNA First)
    ///
    /// REFATORAÇÃO FINAL:
    /// - Totalmente desacoplado de NLP.
    /// - Não conhece string.
    /// - Opera apenas sobre tokens.
    ///
    /// Este motor representa o "Ribossomo Vetorial"
    /// dentro da analogia biológica do Scriptome.
    /// </summary>
    public class MotorDeriva6 : IMotorDeriva
    {
        public string Nome => "DERIVA 6 (RNA-First)";

        private readonly IServicoVocabulario _vocabulario;
        private readonly ParametrosVader _vaderDNA;

        public MotorDeriva6(
            IServicoVocabulario vocabulario,
            ParametrosVader config = null)
        {
            _vocabulario = vocabulario;
            _vaderDNA = config ?? new ParametrosVader();
        }

        public ResultadoDeriva Analisar(
            IReadOnlyList<Token> tokens,
            int rawLength)
        {
            var resultado = new ResultadoDeriva();

            if (tokens == null || tokens.Count == 0 || !_vocabulario.Inicializado)
                return resultado;

            int totalPalavras = tokens.Count(t => !t.EhPontuacao);

            if (totalPalavras == 0)
            {
                resultado.D = resultado.E = resultado.R =
                resultado.I = resultado.V = resultado.A =
                resultado.IE = resultado.S = 0.1;

                return resultado;
            }

            double accD = 0, accE = 0, accR = 0, accI = 0,
                   accV = 0, accA = 0, accS = 0;

            for (int i = 0; i < tokens.Count; i++)
            {
                var t = tokens[i];
                if (t.EhPontuacao) continue;

                var pesos = _vocabulario.ObterPesos(t.Lema);

                if ((pesos == null || pesos.Count == 0) &&
                    t.Lema != t.Normalizado)
                {
                    pesos = _vocabulario.ObterPesos(t.Normalizado);
                }

                if (pesos == null || pesos.Count == 0) continue;

                foreach (var kvp in pesos)
                {
                    double peso =
                        HeuristicaContextual.CalcularScoreAjustado(
                            kvp.Value,
                            tokens,
                            i,
                            _vaderDNA);

                    switch (kvp.Key)
                    {
                        case "DOMINANCIA": accD += peso; break;
                        case "EGO": accE += peso; break;
                        case "RACIONALIDADE": accR += peso; break;
                        case "VOLICAO":
                            accV += peso;
                            if (peso > 0.8) accD += peso * 0.4;
                            break;
                        case "AFETO": accA += peso; break;
                        case "IRONIA": accI += peso; break;
                        case "VISAO":
                        case "AUDICAO":
                        case "TATO":
                        case "OLFATOGOSTO":
                            accS += peso;
                            break;
                    }
                }
            }

            double fatorNorm =
                _vocabulario.ObterConfig("Normalizacao", 200.0);

            resultado.D = Score(accD, totalPalavras, fatorNorm);
            resultado.E = Score(accE, totalPalavras, fatorNorm);
            resultado.R = Score(accR, totalPalavras, fatorNorm);
            resultado.V = Score(accV, totalPalavras, fatorNorm);
            resultado.A = Score(accA, totalPalavras, fatorNorm);
            resultado.S = Score(accS, totalPalavras, fatorNorm);

            resultado.I = Math.Min(10, accI * 1.5);

            double mediaChars =
                (double)rawLength / Math.Max(1, totalPalavras);

            resultado.IE =
                Math.Clamp((mediaChars - 4) * 3.5, 0, 10);

            return resultado;
        }

        private double Score(double acc, int total, double fator)
        {
            return Math.Round(
                Math.Clamp((acc / total) * fator, 0, 10),
                2);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using Scriptome.Limbic.Modelos;
using Scriptome.Limbic.Interfaces;

namespace Scriptome.Limbic.Dados
{
    /// <summary>
    /// IMPLEMENTAÇÃO: Banco de Dados Léxico (Adapter)
    /// DESCRIÇÃO: Implementa IServicoVocabulario encapsulando o RepositorioLexicoUnificado.
    /// PRESERVAÇÃO: Mantém a lógica exata de mapeamento de TermoLexical para vetores (Lacan, VADER, Tags).
    /// </summary>
    public class BancoDeDadosLexico : IServicoVocabulario
    {
        private readonly RepositorioLexicoUnificado _repositorioReal;

        public bool Inicializado => _repositorioReal != null && _repositorioReal.Carregado;

        public BancoDeDadosLexico()
        {
            _repositorioReal = new RepositorioLexicoUnificado();
        }

        public void Carregar(string caminhoCerebro)
        {
            _repositorioReal.Carregar(caminhoCerebro);
        }

        public Dictionary<string, double> ObterPesos(string palavra)
        {
            var termos = _repositorioReal.Buscar(palavra);

            if (termos == null || !termos.Any())
                return new Dictionary<string, double>();

            // Lógica Legada: Prioriza o termo com maior relevância
            var t = termos.OrderByDescending(x => x.PesoRelevancia).First();

            return MapearTermoParaDicionarioLimbico(t);
        }

        public double ObterConfig(string key, double def) => _repositorioReal.GetConfig(key, def);

        // --- LÓGICA CORE PRESERVADA ---
        private Dictionary<string, double> MapearTermoParaDicionarioLimbico(TermoLexical t)
        {
            var dicionario = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);
            double forca = t.Intensidade;
            double valAbs = Math.Abs(t.Valencia);

            // 1. DIMENSÕES VADER
            if (t.Valencia > 0)
            {
                dicionario["AFETO"] = t.Valencia * 2.5;
                dicionario["POSITIVIDADE"] = t.Valencia;
            }
            else if (t.Valencia < 0)
            {
                dicionario["TENSAO"] = valAbs * 2.5;
                dicionario["NEGATIVIDADE"] = valAbs;
            }

            // 2. REGISTROS LACANIANOS
            if (!string.IsNullOrEmpty(t.RegistroLacan))
            {
                dicionario[t.RegistroLacan] = forca;
                if (t.RegistroLacan == "REAL") dicionario["VOLICAO"] = forca;
                if (t.RegistroLacan == "SIMBOLICO") dicionario["RACIONALIDADE"] = forca;
                if (t.RegistroLacan == "IMAGINARIO") dicionario["EGO"] = forca;
            }

            // 3. TAGS PLUTCHIK E CONTEXTO
            if (!string.IsNullOrEmpty(t.EmocaoPlutchik) && t.EmocaoPlutchik != "NEUTRO")
            {
                dicionario[t.EmocaoPlutchik] = forca;
            }
            if (!string.IsNullOrEmpty(t.Contexto) && t.Contexto != "PADRAO")
            {
                dicionario[t.Contexto] = forca;
            }

            // 4. RASTREABILIDADE
            if (!string.IsNullOrEmpty(t.Lema)) dicionario[$"LEMA_{t.Lema}"] = 1.0;
            if (t.EhDesvio) dicionario["DESVIO_LINGUISTICO"] = 1.0;

            // 5. GRAMÁTICA
            switch (t.Gramatica)
            {
                case CategoriaLexica.Numeral:
                    dicionario["LOGOS"] = 1.0;
                    dicionario["RACIONALIDADE"] = Math.Max(dicionario.GetValueOrDefault("RACIONALIDADE"), 2.0);
                    break;
                case CategoriaLexica.Interjeicao:
                    dicionario["SENSORIAL"] = forca;
                    dicionario["INFORMAIS"] = 2.0;
                    break;
                case CategoriaLexica.Adverbio:
                    if (forca > 3.0) dicionario["MODIFICADOR"] = forca;
                    break;
            }

            if (dicionario.Count == 0) dicionario["NEUTRO"] = 0.1;

            return dicionario;
        }
    }
}

using ClosedXML.Excel;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;

namespace Scriptome.Limbic.Dados
{
    public class CarregadorLimbic
    {
        public (Dictionary<string, Dictionary<string, double>> Lexico, Dictionary<string, double> Config) Carregar(string caminhoExcel)
        {
            var lexico = new Dictionary<string, Dictionary<string, double>>(StringComparer.OrdinalIgnoreCase);
            var config = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine($"[DIAGNÓSTICO] Abrindo Cérebro em: {caminhoExcel}");

            if (!File.Exists(caminhoExcel))
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine("[ERRO FATAL] Arquivo não encontrado!");
                throw new FileNotFoundException($"Cérebro Lexical sumiu: {caminhoExcel}");
            }

            try
            {
                using var wb = new XLWorkbook(caminhoExcel);
                int palavrasTotal = 0;

                foreach (var ws in wb.Worksheets)
                {
                    string categoria = ws.Name.ToUpper().Trim();
                    if (categoria == "CONFIG") continue;

                    int countAba = 0;
                    // Pula o cabeçalho (Skip 1)
                    foreach (var row in ws.RowsUsed().Skip(1))
                    {
                        // Tenta ler Coluna 1 (Palavra) e Coluna 2 (Peso)
                        string termo = row.Cell(1).GetValue<string>().Trim().ToUpper();
                        string pesoRaw = row.Cell(2).GetValue<string>();

                        // --- CHECK DE INTEGRIDADE ---
                        // Se o usuário colou CSV, a palavra vai ter ";" ou ","
                        if (termo.Contains(";") || termo.Contains(","))
                        {
                            Console.WriteLine($"[AVISO] Detectado CSV na célula A{row.RowNumber()}: '{termo}'. Tentando corrigir...");
                            var partes = termo.Split(new[] { ';', ',' });
                            termo = partes[0].Trim();
                            if (partes.Length > 1) pesoRaw = partes[1].Trim();
                        }

                        if (string.IsNullOrWhiteSpace(termo)) continue;

                        // Parse do Peso
                        double peso = 1.0;
                        if (double.TryParse(pesoRaw.Replace(".", ","), out double p)) peso = p;
                        else if (double.TryParse(pesoRaw, out double p2)) peso = p2;

                        if (!lexico.ContainsKey(termo))
                            lexico[termo] = new Dictionary<string, double>();

                        lexico[termo][categoria] = peso;
                        countAba++;
                        palavrasTotal++;
                    }
                    Console.WriteLine($"   > Aba {categoria}: {countAba} verbetes carregados.");
                }

                if (palavrasTotal == 0)
                {
                    Console.ForegroundColor = ConsoleColor.Red;
                    Console.WriteLine("[ALERTA] O Excel foi lido, mas NENHUMA palavra foi extraída. Verifique se os dados começam na Linha 2.");
                }
                else
                {
                    Console.ForegroundColor = ConsoleColor.Green;
                    Console.WriteLine($"[SUCESSO] Cérebro Ativo: {palavrasTotal} conexões sinápticas prontas.");
                }
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"[ERRO EXCEL] {ex.Message}");
                throw;
            }
            Console.ResetColor();

            return (lexico, config);
        }
    }
}

using System;
using System.IO;
using System.Text.Json;

namespace Scriptome.Limbic.Dados
{
    public static class ConfiguradorLimbic
    {
        private const string ARQUIVO_CONFIG = "vader_config.json";

        public static ParametrosVader Carregar(string diretorioBase)
        {
            string caminho = Path.Combine(diretorioBase, "Data", "Config", ARQUIVO_CONFIG);

            // Fallback: Se não existe, cria o default
            if (!File.Exists(caminho))
            {
                var padrao = new ParametrosVader();
                Salvar(padrao, diretorioBase);
                return padrao;
            }

            try
            {
                string jsonString = File.ReadAllText(caminho);
                return JsonSerializer.Deserialize<ParametrosVader>(jsonString);
            }
            catch (Exception ex)
            {
                Console.WriteLine($"[ERRO] Falha ao ler config VADER: {ex.Message}. Usando padrão.");
                return new ParametrosVader();
            }
        }

        // Útil para o Algoritmo Genético salvar a "melhor geração"
        public static void Salvar(ParametrosVader config, string diretorioBase)
        {
            string pasta = Path.Combine(diretorioBase, "Data", "Config");
            Directory.CreateDirectory(pasta);

            string caminho = Path.Combine(pasta, ARQUIVO_CONFIG);
            string jsonString = JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });

            File.WriteAllText(caminho, jsonString);
        }
    }
}

