using System.Collections.Generic;

namespace Scriptome.Linguistica
{
    public class LematizadorHibrido
    {
        // Mini-banco de verbos irregulares frequentes em Roteiros (Fase 1)
        // Isso evita erros graves de sentido.
        private static readonly Dictionary<string, string> _irregulares = new Dictionary<string, string>
        {
            // Ser/Estar (Críticos para Ego e Estado)
            {"SOU", "SER"}, {"ÉS", "SER"}, {"É", "SER"}, {"SOMOS", "SER"}, {"SÃO", "SER"}, {"ERA", "SER"}, {"FUI", "SER"},
            {"ESTOU", "ESTAR"}, {"ESTÁ", "ESTAR"}, {"ESTAVA", "ESTAR"}, {"ESTEVE", "ESTAR"},
            
            // Verbos de Ação Comuns
            {"VOU", "IR"}, {"VAI", "IR"}, {"IA", "IR"}, {"INDO", "IR"},
            {"TENHO", "TER"}, {"TEM", "TER"}, {"TINHA", "TER"},
            {"FIZ", "FAZER"}, {"FAZ", "FAZER"}, {"FEZ", "FAZER"}, {"FACO", "FAZER"},
            {"DISSE", "DIZER"}, {"DIZ", "DIZER"}, {"DIRIA", "DIZER"},
            {"VEJO", "VER"}, {"VIU", "VER"}, {"VISTA", "VER"},
            {"OUCO", "OUVIR"}, {"OUVIU", "OUVIR"},
            {"QUIS", "QUERER"}, {"QUER", "QUERER"},
            {"HÁ", "HAVER"}, {"HOUVE", "HAVER"},
            {"SEI", "SABER"}, {"SABE", "SABER"}, {"SOUBE", "SABER"},
            {"POSSO", "PODER"}, {"PODE", "PODER"}, {"PUDE", "PODER"}
        };

        // Sufixos ordenados por tamanho (Estratégia do Stemmer antigo, refinada)
        private static readonly string[] _sufixosVerbais = new[]
        {
            "REMOS", "RÍAM", "RIAM", "REIS", "SSE", "STE", "RAM", "RÃO", "AVA", "IAM",
            "NDO", "ADO", "IDO", "AR", "ER", "IR" // Infinitivos e gerúndios
        };

        public string Lematizar(string palavra)
        {
            if (string.IsNullOrEmpty(palavra)) return "";
            string termo = palavra.ToUpper();

            // 1. Lookup de Irregulares (Preciso)
            if (_irregulares.TryGetValue(termo, out string raizIrregular))
                return raizIrregular;

            // 2. Regras Morfológicas (Heurística)
            // Se termina em 'S' (Plurais simples), tenta singular
            if (termo.EndsWith("S") && termo.Length > 4 && !termo.EndsWith("SS"))
            {
                // Ex: "ARMAS" -> "ARMA". Mas cuidado com "DEUS", "MAIS" (Exceções tratadas no MotorLimbic ou aqui)
                // Vamos deixar o Stemmer cuidar disso ou implementar lógica de plural aqui.
            }

            // 3. Fallback: O Stemmer que já criamos (integrado aqui)
            // Tenta remover sufixos verbais padrão
            foreach (var sufixo in _sufixosVerbais)
            {
                if (termo.EndsWith(sufixo) && termo.Length > sufixo.Length + 3) // Raiz min 3 chars
                {
                    return termo.Substring(0, termo.Length - sufixo.Length) + ObterTerminacaoProvavel(sufixo);
                }
            }

            return termo;
        }

        // Tenta adivinhar se devolve "AR", "ER" ou "IR" baseado no sufixo cortado
        // Ex: "AMANDO" (-NDO) -> AM + AR = AMAR. "CORRENDO" -> CORR + ER = CORRER.
        private string ObterTerminacaoProvavel(string sufixoRemovido)
        {
            // Heurística simples: se cortou sufixo verbal, devolve "R" para tentar bater no infinitivo do Excel
            // O ideal seria repor a vogal temática (A, E, I), mas isso exige análise complexa.
            // Para o Scriptome, devolver a raiz crua muitas vezes bate no Excel (ex: "AM" bate em "AMA"? Não.)
            // Vamos adotar a estratégia de normalizar para infinitivo "R" se possível.

            if (sufixoRemovido == "NDO" || sufixoRemovido == "ADO") return "AR"; // Maioria
            return "R"; // Genérico
        }
    }
}

using System.Collections.Generic;
using System.Text.RegularExpressions;
using System.Linq;
using System;

namespace Scriptome.Linguistica
{
    public class ProcessadorLinguistico : IPipelineLinguistico
    {
        private readonly LematizadorHibrido _lematizador;

        public ProcessadorLinguistico()
        {
            _lematizador = new LematizadorHibrido();
        }

        public List<Token> Processar(string texto)
        {
            var tokens = new List<Token>();
            if (string.IsNullOrWhiteSpace(texto)) return tokens;

            // 1. Tokenização Inteligente (Regex)
            // Separa palavras de pontuações, mantendo tudo.
            // Padrão: Palavras (\w+) OU Pontuações (! ? , .)
            string padrao = @"([\w]+|[!?,.;:]+)";

            var matches = Regex.Matches(texto, padrao);

            int indice = 0;
            foreach (Match match in matches)
            {
                string valor = match.Value;
                if (string.IsNullOrWhiteSpace(valor)) continue;

                var t = new Token
                {
                    Indice = indice++,
                    Original = valor,
                    CaixaAlta = IsAllUpper(valor) && valor.Length > 1,
                    EhPontuacao = !char.IsLetterOrDigit(valor[0]),
                    Normalizado = valor.ToUpper()
                };

                // 2. Processamento Linguístico (Só se for palavra)
                if (!t.EhPontuacao)
                {
                    // Tenta obter o LEMA (Raiz)
                    t.Lema = _lematizador.Lematizar(t.Normalizado);
                }
                else
                {
                    t.Lema = t.Normalizado; // Pontuação é o próprio lema
                }

                tokens.Add(t);
            }

            return tokens;
        }

        private bool IsAllUpper(string input)
        {
            foreach (char c in input) if (char.IsLetter(c) && !char.IsUpper(c)) return false;
            return true;
        }
    }
}

