using Scriptome.Nucleo.Modelos.Analise;
using System;
using System.Collections.Generic;
using System.Text;

namespace Scriptome.Limbic.Pipeline
{
    // === COMPONENTE 4: MOTOR DE FUSÃO ===
    public class MotorDeFusao
    {
        public PerfilPersonagem Fundir(string nome, AcumuladorForense f, int cenas)
        {
            int n = f.Falas;
            int div = (n == 0) ? 1 : n;
            var p = new PerfilPersonagem { Nome = nome, QuantidadeFalas = n };

            // Vetores Léxicos
            double domLex = f.SomaD / div;
            double volLex = f.SomaV / div;
            double egoLex = f.SomaE / div;
            double senLex = f.SomaS / div;
            double afeLex = f.SomaA / div;
            double iroLex = f.SomaI / div;
            double racLex = f.SomaR / div;

            // Vetores Contextuais (Log)
            int c = Math.Max(1, cenas);
            double domCtx = LogScore(f.CtxDom / c);
            double senCtx = LogScore(f.CtxSen / c);
            double egoCtx = LogScore(f.CtxEgo / c);
            double iroCtx = LogScore(f.CtxIro / c);
            double volCtx = LogScoreSigned(f.CtxVol / c);
            double afeCtx = LogScoreSigned(f.CtxAfe / c);

            // Fusão
            double influencia = domCtx / (domCtx + domLex + 0.1);
            double pesoVerbal = 0.4 - (influencia * 0.2);
            double pesoContextual = 0.3 + (influencia * 0.3);

            double domRelacional = (volLex * 0.4) + (iroLex * 0.3) + (egoLex * 0.3);
            double domSensorial = (senLex * 0.4) + (senCtx * 0.3) + (volLex * 0.2);
            double domFinal = (domLex * pesoVerbal) + (domCtx * pesoContextual) + (domRelacional * 0.15) + (domSensorial * 0.15);

            p.ScoreDominancia = Clamp(domFinal);
            p.ScoreSensorium = Clamp((senLex * 0.5) + (senCtx * 0.5));
            p.ScoreAfeto = Clamp((afeLex * 0.6) + (Math.Max(0, afeCtx) * 0.4));
            p.ScoreIronia = Clamp((iroLex * 0.7) + (iroCtx * 0.3));
            p.ScoreEgo = Clamp((egoLex * 0.7) + (egoCtx * 0.3));
            p.ScoreVolicao = Clamp((volLex * 0.6) + (Math.Abs(volCtx) * 0.3) + (domCtx * 0.1));

            p.ScoreRacionalidade = Math.Round(racLex, 2);
            p.ScoreErudicao = Math.Round(f.SomaIE / div, 2);
            p.BurstMedio = Math.Round(f.SomaBurst / div, 1);
            p.DramatismoMedio = Math.Round(f.SomaLimbic / div, 1);

            p.KarmaMoral = (p.ScoreAfeto * 2.0) - (p.ScoreDominancia + p.ScoreEgo);
            p.KarmaOrdem = (p.ScoreRacionalidade * 2.0) - (p.ScoreVolicao + p.ScoreIronia);
            p.AlinhamentoMoral = $"{(p.KarmaOrdem > 0 ? "Ordem" : "Caos")} / {(p.KarmaMoral > 0 ? "Bem" : "Mal")}";

            return p;
        }

        private double LogScore(double val) => Math.Min(10, Math.Log(1 + Math.Max(0, val)) * 4.0);
        private double LogScoreSigned(double val) => Math.Min(10, Math.Log(1 + Math.Abs(val)) * 4.0) * Math.Sign(val);
        private double Clamp(double val) => Math.Round(Math.Max(0, Math.Min(10, val)), 2);
    }

}

using Scriptome.Limbic.Motor;
using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Script;
using Scriptome.Nucleo.Modelos.Genoma;

namespace Scriptome.Limbic.Pipeline
{
    /// <summary>
    /// PIPELINE LÍMBICO (RNA-First)
    ///
    /// Orquestra os componentes:
    /// - ConstrutorDeCena
    /// - AnalisadorLexico
    /// - AnalisadorContextual
    ///
    /// Não contém lógica analítica.
    /// Apenas coordenação.
    /// </summary>
    public class PipelineLimbic
    {
        private readonly ConstrutorDeCena _construtor;
        private readonly AnalisadorLexico _lexico;
        private readonly AnalisadorContextual _contextual;

        public PipelineLimbic(
            MotorLimbic motor,
            MotorDeTranscricao transcritor)
        {
            _construtor = new ConstrutorDeCena();

            _lexico = new AnalisadorLexico(
                motor,
                transcritor);

            _contextual = new AnalisadorContextual(
                motor,
                transcritor);
        }

        public void ProcessarCena(
            Cena cena,
            EstatisticasRoteiro stats,
            ContextoLimbic ctx)
        {
            _construtor.Inicializar(cena, stats, ctx);

            foreach (var elemento in cena.Elementos)
            {
                if (elemento is Dialogo d)
                    _lexico.Processar(d, ctx);

                else if (elemento is Acao a)
                    _contextual.Processar(a, ctx);
            }

            _construtor.Finalizar(ctx);
        }
    }
}

using Scriptome.Limbic.Algoritmos;
using Scriptome.Limbic.Dados;
using Scriptome.Limbic.Interfaces;
