using Scriptome.Nucleo.Modelos.Genoma;
using System;

namespace Scriptome.Testes
{
    public static class VerificadorLimbic
    {
        public static void ExecutarTeste(string baseDir)
        {
            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine("\n=== INICIANDO TESTES LIMBIC (RNA-First) ===");
            Console.ResetColor();

            Console.WriteLine("[SETUP] Inicializando dependências...");

            IServicoVocabulario vocab = new BancoDeDadosLexico();
            string caminhoVocab = System.IO.Path.Combine(baseDir, "Data", "Sandbox");
            vocab.Carregar(caminhoVocab);

            if (!vocab.Inicializado)
            {
                Erro("Falha ao carregar vocabulário. Testes abortados.");
                return;
            }

            var configVader = new ParametrosVader();
            IMotorDeriva deriva = new MotorDeriva6(vocab, configVader);
            IMotorLimbic motor = new MotorLimbic(vocab, deriva);

            TesteDerivaPura(deriva);
            VerificadorDerivaCompleto.Executar(deriva);
            TesteMotorCompleto(motor);

            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine("=== FIM DOS TESTES ===\n");
            Console.ResetColor();
        }

        private static ResultadoDeriva ExecutarDeriva(
            IMotorDeriva engine,
            string texto)
        {
            var pipeline = new ProcessadorLinguistico();
            var tokens = pipeline.Processar(texto);

            return engine.Analisar(tokens, texto.Length);
        }

        private static ResultadoLimbic ExecutarLimbic(
            IMotorLimbic motor,
            string texto)
        {
            var transcritor = new MotorDeTranscricao(
                new ProcessadorLinguistico());

            var gene = new GeneDiscursivo(texto, 0, 0);
            var dna = new BaseImutavel("TESTE", new[] { gene });
            var rna = transcritor.Transcrever(dna);

            return motor.Processar(rna);
        }

        private static void TesteDerivaPura(IMotorDeriva engine)
        {
            Console.WriteLine("\n[TESTE 1] Engine DERIVA Pura");

            string input =
                "Eu vou destruir tudo o que você ama com ódio e fúria!";

            var resultado = ExecutarDeriva(engine, input);

            Assert("Dominância > 0", resultado.D > 0);
            Assert("Volição > 0", resultado.V > 0);
            Assert("Afeto Alto (Carga Emocional)", resultado.A > 5.0);

            Console.WriteLine($"   Vetores: D={resultado.D:F1}, V={resultado.V:F1}, A={resultado.A:F1}");
        }

        private static void TesteMotorCompleto(IMotorLimbic motor)
        {
            Console.WriteLine("\n[TESTE 2] Motor Limbic Completo");

            string input =
                "NÃO!!! SAI DAQUI AGORA SEU IDIOTA!!!";

            var resultado = ExecutarLimbic(motor, input);

            Assert("Burst Score Alto", resultado.ScoreB > 50);
            Assert("Dramatismo Calculado", resultado.DramatismoTotal > 0);
            Assert("Metadados Preenchidos",
                resultado.PalavrasChave.Contains("ALTA TENSÃO") ||
                resultado.PalavrasChave.Contains("DOMINANTE"));

            Console.WriteLine(
                $"   Burst: {resultado.ScoreB:F1} | Drama: {resultado.DramatismoTotal:F1}");
        }

        private static void Assert(string nome, bool condicao)
        {
            if (condicao)
            {
                Console.ForegroundColor = ConsoleColor.Green;
                Console.WriteLine($"   [PASS] {nome}");
            }
            else
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"   [FAIL] {nome}");
            }

            Console.ResetColor();
        }

        private static void Erro(string msg)
        {
            Console.ForegroundColor = ConsoleColor.Red;
            Console.WriteLine($"[ERRO CRÍTICO] {msg}");
            Console.ResetColor();
        }
    }
}

